294. /// <summary>
295. /// Strategies for humanizing date/time differences.
296. /// </summary>
297. public sealed class DefaultDateTimeHumanizeStrategy
298. {
299.     /// <summary>
300.     /// Humanizes a DateTime difference relative to a base date.
301.     /// </summary>
302.     /// <param name="input">The date to humanize.</param>
303.     /// <param name="comparedTo">The reference date (typically DateTime.UtcNow).</param>
304.     /// <returns>A human-readable string representing the time difference.</returns>
305.     public string Humanize(DateTime input, DateTime comparedTo)
306.     {
307.         var difference = comparedTo - input;
308.         if (Math.Abs(difference.TotalSeconds) < 2)
309.         {
310.             return "just now";
311.         }
312. 
313.         var isFuture = difference.TotalSeconds < 0;
314.         var absDiff = difference.Duration();
315. 
316.         var result = absDiff.TotalDays switch
317.         {
318.             >= 365 => $"{(int)(absDiff.TotalDays / 365)} years",
319.             >= 31 => $"{(int)(absDiff.TotalDays / 30)} months",
320.             >= 1 => $"{(int)absDiff.TotalDays} days",
321.             _ => absDiff.TotalHours switch
322.             {
323.                 >= 1 => $"{(int)absDiff.TotalHours} hours",
324.                 _ => absDiff.TotalMinutes switch
325.                 {
326.                     >= 1 => $"{(int)absDiff.TotalMinutes} minutes",
327.                     _ => $"{(int)absDiff.TotalSeconds} seconds"
328.                 }
329.             }
330.         };
331. 
332.         return isFuture ? $"in {result}" : $"{result} ago";
333.     }
334. }
